patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 6babfd1eee91..a3d4dcaac420 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7289,14 +7289,20 @@ planContainsAdditionalSimplifications(VPlan &Plan, ElementCount VF,
         return any_of(*BB, [&SeenInstrs, VF, &CostCtx, &CM](Instruction &I) {
           if (isa<PHINode>(&I))
             return false;
-          return !SeenInstrs.contains(&I) &&
-                 !CostCtx.skipCostComputation(&I, true) &&
-                 !CM.canTruncateToMinimalBitwidth(&I, VF);
+          bool HasUnaccountedInstr = !SeenInstrs.contains(&I) &&
+                                     !CostCtx.skipCostComputation(&I, true) &&
+                                     !CM.canTruncateToMinimalBitwidth(&I, VF);
+          bool HasTruncToI1ForBranch = isa<TruncInst>(&I) && 
+                                       I.getType()->isIntegerTy(1) &&
+                                       all_of(I.users(), [](User *U) { 
+                                         return isa<Instruction>(U) && 
+                                                cast<Instruction>(U)->isTerminator(); 
+                                       });
+          return HasUnaccountedInstr || HasTruncToI1ForBranch;
         });
       });
 }
 #endif
-
 VectorizationFactor LoopVectorizationPlanner::computeBestVF() {
   if (VPlans.empty())
     return VectorizationFactor::Disabled();

